• To setup a connection from the browser 
• Create a new WebSocket object with the host/path 
to connect to 
• Choose a path and setup your server to accept 
WS requests on that path
Web Sockets - Browser
let socket = new WebSocket('ws://' + window.location.host + '/socket');
socket.onmessage = renderMessages;
function sendMessage() {
    socket.send(JSON.stringify({'username': username, 'message': message}))
}
function renderMessages(message) {
    console.log(message.data);
}

• Set onmessage to a function that will be 
called whenever a message is received 
• The argument of the call will contain the 
message
let socket = new WebSocket('ws://' + window.location.host + '/socket');
socket.onmessage = renderMessages;
function sendMessage() {
    socket.send(JSON.stringify({'username': username, 'message': message}))
}
function renderMessages(message) {
    console.log(message.data);
}
